    },
    {
      "source_requirement": "Transition from Door Open with Item to Door Shut with Item when user closes the door",
      "rewritten_requirement": "The system shall transition from the Door Open with Item state to the Door Shut with Item state when the user closes the door."
    },
    {
      "source_requirement": "Enter Ready to Cook state after user inputs cooking time",
      "rewritten_requirement": "The system shall enter the Ready to Cook state after the user inputs the cooking time."
    },
    {
      "source_requirement": "Transition from Ready to Cook to Cooking when user presses Start button",
      "rewritten_requirement": "The system shall transition from the Ready to Cook state to the Cooking state when the user presses the Start button."
    },
    {
      "source_requirement": "Leave Cooking state and reenter Door Shut with Item when timer expires",
      "rewritten_requirement": "The system shall leave the Cooking state and reenter the Door Shut with Item state when the timer expires."
    },
    {
      "source_requirement": "Transition from Cooking to Door Open with Item if door is opened during cooking",
      "rewritten_requirement": "The system shall transition from the Cooking state to the Door Open with Item state if the door is opened during cooking."
    }
  ]
}
